:"26022602-03","product_model":"03-24","length_mm":110,"operation":"冲孔1","standard_seconds":10,"incoming_qualified_quantity":1638,"qualified_quantity":1637,"defect_quantity_1":1,"defect_reason_1":"加工","defect_quantity_2":0,"defect_reason_2":"原料","data_category":"A","remark":null},{"employee_id":"9d231831-c47a-40a8-9d11-4d18915be774","order_date":"2026-03-10","project_no":"26022504-04","product_model":"213-553","length_mm":1960,"operation":"冲葫芦孔","standard_seconds":15,"incoming_qualified_quantity":601,"qualified_quantity":601,"defect_quantity_1":0,"defect_reason_1":null,"defect_quantity_2":0,"defect_reason_2":"原料","data_category":"A","remark":null}]$item_json$)
    as x(
      employee_id uuid,
      order_date date,
      project_no text,
      product_model text,
      length_mm numeric,
      operation text,
      standard_seconds numeric,
      incoming_qualified_quantity integer,
      qualified_quantity integer,
      defect_quantity_1 integer,
      defect_reason_1 text,
      defect_quantity_2 integer,
      defect_reason_2 text,
      data_category text,
      remark text
    )
), prepared_items as (
  select
    o.id as order_id,
    i.project_no,
    i.product_model,
    case
      when so.product_model = i.product_model then coalesce(so.length_mm, i.length_mm)
      else i.length_mm
    end as length_mm,
    case
      when so.product_model = i.product_model then so.customer_model
      else null
    end as customer_model,
    i.operation,
    i.standard_seconds,
    i.incoming_qualified_quantity,
    i.qualified_quantity,
    i.defect_quantity_1,
    i.defect_reason_1,
    i.defect_quantity_2,
    i.defect_reason_2,
    i.data_category,
    i.remark
  from item_seed i
  join target_orders o
    on o.employee_id = i.employee_id
   and o.order_date = i.order_date
  left join public.sales_orders so
    on so.project_no = i.project_no
), inserted_items as (
  insert into public.production_order_items (
    order_id,
    project_no,
    product_model,
    length_mm,
    customer_model,
    operation,
    standard_seconds,
    incoming_qualified_quantity,
    qualified_quantity,
    defect_quantity_1,
    defect_reason_1,
    defect_quantity_2,
    defect_reason_2,
    data_category,
    remark
  )
  select
    p.order_id,
    p.project_no,
    p.product_model,
    p.length_mm,
    p.customer_model,
    p.operation,
    p.standard_seconds,
    p.incoming_qualified_quantity,
    p.qualified_quantity,
    p.defect_quantity_1,
    p.defect_reason_1,
    p.defect_quantity_2,
    p.defect_reason_2,
    p.data_category,
    p.remark
  from prepared_items p
  where not exists (
    select 1
    from public.production_order_items poi
    where poi.order_id = p.order_id
      and coalesce(poi.project_no, '') = coalesce(p.project_no, '')
      and poi.product_model = p.product_model
      and coalesce(poi.length_mm, -1) = coalesce(p.length_mm, -1)
      and coalesce(poi.customer_model, '') = coalesce(p.customer_model, '')
      and poi.operation = p.operation
      and poi.qualified_quantity = p.qualified_quantity
      and coalesce(poi.defect_quantity_1, 0) = coalesce(p.defect_quantity_1, 0)
  )
  returning id
)
select
  34::integer as expected_orders,
  82::integer as expected_items,
  (select count(*) from inserted_orders) as inserted_orders,
  (select count(*) from inserted_items) as inserted_items;
